#!/usr/bin/env perl

use strict;
use warnings;
use File::Spec;
use File::Basename;
use Cwd 'abs_path';

my $config_dir = $ENV{PLUGIN_CONFIG_DIR} || './plugins';
my %plugins;
my %plugin_hooks;

sub load_plugins {
    my ($dir) = @_;
    $dir ||= $config_dir;
    
    unless (-d $dir) {
        warn "Plugin directory not found: $dir\n";
        return;
    }
    
    opendir(my $dh, $dir) or die "Cannot open plugin directory: $!\n";
    my @files = grep { /\.pl$/ && -f "$dir/$_" } readdir($dh);
    closedir($dh);
    
    foreach my $file (@files) {
        my $path = File::Spec->catfile($dir, $file);
        load_plugin($path);
    }
}

sub load_plugin {
    my ($path) = @_;
    
    open(my $fh, '<', $path) or do {
        warn "Cannot open plugin file $path: $!\n";
        return;
    };
    
    my $plugin_code = do { local $/; <$fh> };
    close($fh);
    
    my $plugin_name = basename($path, '.pl');
    
    eval {
        my $result = eval($plugin_code);
        if ($@) {
            die "Plugin compilation error: $@";
        }
        
        $plugins{$plugin_name} = {
            code => $plugin_code,
            path => $path,
            loaded => time(),
        };
        
        print "Loaded plugin: $plugin_name\n";
    };
    
    if ($@) {
        warn "Failed to load plugin $plugin_name: $@\n";
    }
}

sub reload_plugin {
    my ($plugin_name) = @_;
    
    if (exists $plugins{$plugin_name}) {
        my $path = $plugins{$plugin_name}{path};
        delete $plugins{$plugin_name};
