    };
    
    if ($@) {
        warn "Failed to execute plugin $plugin_name: $@\n";
        return;
    }
    
    return 1;
}

sub register_hook {
    my ($hook_name, $callback) = @_;
    push @{$plugin_hooks{$hook_name}}, $callback;
}

sub execute_hook {
    my ($hook_name, @args) = @_;
    
    return unless exists $plugin_hooks{$hook_name};
    
    my @results;
    foreach my $callback (@{$plugin_hooks{$hook_name}}) {
        eval {
            my $result = $callback->(@args);
            push @results, $result;
        };
        warn "Hook execution error: $@\n" if $@;
    }
    
    return @results;
}

sub list_plugins {
